async (page) => {
  // 1. Open inventory panel
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(800);
  // 2. Click item slot 0 (Bronze Axe)
  await page.evaluate((idx) => {
    const slots = document.querySelectorAll('.item-slot');
    if (slots[idx]) slots[idx].click();
  }, 0);
  await page.waitForTimeout(800);
  // 3. Click equip button
  await page.evaluate(() => {
    const btn = document.querySelector('.action-equip');
    if (btn) btn.click();
  });
  await page.waitForTimeout(500);
  // 4. Close inventory
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(500);
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return 'Equipped Bronze Axe';
}

async (page) => {
  // Click on the rat visible on the left side of screen (~112, 390 based on screenshot)
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Walk left toward rat first
  await click(112, 390);
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return 'Clicked at rat location';
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Click on the visible rat on the left side (visually ~350, 290)
  await click(350, 290);
  await page.waitForTimeout(5000);

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      pos: gs.player_position,
      stats: gs.player_stats,
      target: gs.current_target,
      last_xp: gs.last_xp_event
    });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return state;
}

